# ---------- Feedback Functions ----------
def load_feedback():
    if os.path.exists(FEEDBACK_FILE):
        try:
            with open(FEEDBACK_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
        except Exception:
            return []
    return []


def save_feedback(query, video_link, rating, comment=""):
    # ✅ حفظ في قاعدة البيانات + JSON كـ backup
    try:
        video_id = video_link.split("/")[-1].replace(".mp4", "") if video_link else "unknown"
        db_save_feedback(video_id=video_id, query=query, feedback_type=rating)
    except Exception:
        pass
    # JSON backup
    feedback = load_feedback()
    entry = {
        "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "query": query,
        "video_link": video_link,
        "rating": rating,
        "comment": comment
    }
    feedback.append(entry)
    if len(feedback) > 1000:
        feedback = feedback[-1000:]
    try:
        os.makedirs(os.path.dirname(FEEDBACK_FILE), exist_ok=True)
        with open(FEEDBACK_FILE, 'w', encoding='utf-8') as f:
            json.dump(feedback, f, ensure_ascii=False, indent=2)
        return True
    except Exception:
        return False


def get_feedback_stats():
    # ✅ يقرأ من قاعدة البيانات أولاً
    try:
        db_stats = db_get_feedback_stats()
        total = db_stats["total"] or 0
        thumbs_up = db_stats["positive"] or 0
        thumbs_down = db_stats["negative"] or 0
        satisfaction_rate = (thumbs_up / total * 100) if total > 0 else 0
        return {"total": total, "thumbs_up": thumbs_up, "thumbs_down": thumbs_down, "satisfaction_rate": satisfaction_rate}
    except Exception:
        pass
    # fallback: JSON
    feedback = load_feedback()
    if not feedback:
        return {"total": 0, "thumbs_up": 0, "thumbs_down": 0, "satisfaction_rate": 0}
    thumbs_up = sum(1 for f in feedback if f["rating"] == "up")
    thumbs_down = sum(1 for f in feedback if f["rating"] == "down")
    total = len(feedback)
    satisfaction_rate = (thumbs_up / total * 100) if total > 0 else 0
    return {"total": total, "thumbs_up": thumbs_up, "thumbs_down": thumbs_down, "satisfaction_rate": satisfaction_rate}


