# ============================================================
#              IMAGE SEARCH
# ============================================================
def image_search(image, top_k=10):
    """
    Image Search v4 - Maximum Accuracy
    85% Video + 15% Text + Multi-signal re-ranking
    """
    df = load_dataset()
    text_embs, _ = build_or_load_embeddings(df, verbose=False)

    from ai_engine_v9 import _load_video_embeddings
    video_embs, video_links = _load_video_embeddings()

    # ✅ استخدم image_clip_model (متوافق مع video_embeddings.npy)
    image_input = image_clip_processor(image).unsqueeze(0).to(device)
    with torch.no_grad():
        img_feat = image_clip_model.encode_image(image_input)
        img_feat = img_feat / img_feat.norm(dim=-1, keepdim=True)
    img_feat = img_feat.cpu().numpy()[0]

    if video_embs is not None and video_links is not None:
        text_norms = np.linalg.norm(text_embs, axis=1, keepdims=True) + 1e-8
        text_embs_n = text_embs / text_norms
        video_norms = np.linalg.norm(video_embs, axis=1, keepdims=True) + 1e-8
        video_embs_n = video_embs / video_norms
        img_norm = np.linalg.norm(img_feat) + 1e-8
        img_feat_n = img_feat / img_norm

        text_sims = np.dot(text_embs_n, img_feat_n).astype(float)
        video_sims = np.dot(video_embs_n, img_feat_n).astype(float)

        link_to_video_score = {
            str(video_links[i]).strip(): float(video_sims[i])
            for i in range(len(video_links))
        }

        results = []
        for i, row in df.iterrows():
            link = str(row.get("Link", "")).strip()
            text_score = float(text_sims[i])
            video_score = link_to_video_score.get(link, text_score)

            base_score = 0.85 * video_score + 0.15 * text_score

            # ✅ Lowered thresholds for better results
            if video_score > 0.35:
                video_bonus = 0.06
            elif video_score > 0.25:
                video_bonus = 0.04
            elif video_score > 0.18:
                video_bonus = 0.02
            else:
                video_bonus = 0.0

            text_bonus = 0.05 * (text_score - 0.25) if text_score > 0.25 else 0.0
            combined_bonus = 0.03 if (video_score > 0.20 and text_score > 0.20) else 0.0
            final_score = base_score + video_bonus + text_bonus + combined_bonus

            # ✅ Lowered from 0.08 to 0.05
            if final_score > 0.05:
                cap = str(row.get("Caption", ""))
                results.append({
                    "title": str(row.get("Title", "")),
                    "caption": (cap[:300] + "...") if len(cap) > 300 else cap,
                    "link": link,
                    "score": round(final_score, 3),
                    "text_score": round(text_score, 3),
                    "video_score": round(video_score, 3),
                    "matched_keywords": [],
                })

        results = sorted(results, key=lambda x: x["score"], reverse=True)[:top_k]
        avg = round(float(np.mean([r["score"] for r in results])), 3) if results else 0.0

    else:
        img_norm = np.linalg.norm(img_feat) + 1e-8
        img_feat_n = img_feat / img_norm
        text_norms = np.linalg.norm(text_embs, axis=1, keepdims=True) + 1e-8
        text_embs_n = text_embs / text_norms
        sims = np.dot(text_embs_n, img_feat_n)
        df = df.copy()
        df["score"] = sims
        best = df.sort_values("score", ascending=False).head(top_k)
        results = []
        for _, row in best.iterrows():
            cap = str(row.get("Caption", ""))
            results.append({
                "title": str(row.get("Title", "")),
                "caption": (cap[:300] + "...") if len(cap) > 300 else cap,
                "link": str(row.get("Link", "")),
                "score": round(float(row["score"]), 3),
                "matched_keywords": [],
            })
        avg = round(float(best["score"].mean()), 3) if len(best) > 0 else 0.0

    return results, avg



# ============================================================
#              ARABIC ↔ ENGLISH DICTIONARY
# ============================================================
