EN_TO_AR = {v: k for k, v in AR_TO_EN.items()}


def fuzzy_match_arabic(text):
    """مطابقة ذكية: تجد أقرب كلمة في القاموس حتى لو Whisper كتبها غلط"""
    text_clean = text.strip()

    # 1. تطابق مباشر
    for ar, en in sorted(AR_TO_EN.items(), key=lambda x: -len(x[0])):
        if ar in text_clean:
            return en, ar

    # 2. fuzzy matching - نقارن الأحرف
    try:
        best_match = None
        best_score = 0
        for ar_word in AR_TO_EN.keys():
            # نحسب عدد الأحرف المشتركة
            common = sum(1 for c in text_clean if c in ar_word)
            if len(ar_word) == 0:
                continue
            score = common / max(len(ar_word), len(text_clean))
            if score > best_score and score > 0.5:  # 50% تشابه كافي
                best_score = score
                best_match = ar_word
        if best_match:
            return AR_TO_EN[best_match], best_match
    except Exception:
        pass

    return None, None


def translate_ar_to_en(text):
    result = text
    for ar, en in sorted(AR_TO_EN.items(), key=lambda x: -len(x[0])):
        if ar in result:
            result = result.replace(ar, en)
    return result.strip()


def translate_en_to_ar(text):
    result = text
    for en, ar in sorted(EN_TO_AR.items(), key=lambda x: -len(x[0])):
        if en.lower() in result.lower():
            result = result + f"\n🔄 بالعربي: {ar}"
            break
    return result


