GROQ_API_KEY = st.secrets["GROQ_API_KEY"]

def chatbot_reply(user_msg, history=None):
    if history is None:
        history = []

    # ✅ كشف اللغة بدقة
    arabic_chars = sum(1 for c in user_msg if '\u0600' <= c <= '\u06ff')
    english_chars = sum(1 for c in user_msg if c.isascii() and c.isalpha())
    is_arabic = arabic_chars > english_chars

    # ✅ System prompt يختلف حسب اللغة تماماً
    if is_arabic:
        system_prompt = """أنت المساعد الذكي لمشروع التخرج "Soft Video Search".
**مهم جداً: يجب أن ترد بالعربية فقط في كل الأحوال.**

قواعد:
- أجب على كل سؤال، لا ترفض أي شيء
- إذا كان السؤال عاماً، أجب مختصراً واربطه بالمشروع
- استخدم العربية الفصحى الطبيعية — احتفظ بالمصطلحات التقنية فقط (CLIP, MSR-VTT, Top-1, ViT)
- اجعل إجابتك 2-3 جمل فقط بدون تكرار

حقائق المشروع:
- الاسم: Soft Video Search — بحث دلالي في الفيديوهات
- الداتاسيت: MSR-VTT — 7,010 فيديو تدريب
- النموذج: CLIP ViT-B/32 مدرَّب على MSR-VTT
- طرق البحث الأربع: نصي، صوري، صوتي، شات بوت
- محرك التقييم: 9 إشارات مجمّعة
- الدقة: Top-1: 88.5% | Top-5: 98.0% | Top-10: 99.5%
- دقة التدريب: 99.8% | التحقق: 98.0%
- البحث الصوتي: faster-whisper (يعمل بدون إنترنت)"""
        lang_instruction = "\n[أجب بالعربية فقط]"
    else:
        system_prompt = """You are the AI assistant for the graduation project "Soft Video Search".
**IMPORTANT: Always reply in English only.**

Rules:
- Answer every question — never refuse
- If the question is general, answer briefly and connect it to the project
- Keep answers to 2-3 sentences, no repetition

Project Facts:
- Name: Soft Video Search — semantic video retrieval
- Dataset: MSR-VTT — 7,010 training videos
- Model: CLIP ViT-B/32 fine-tuned on MSR-VTT
- Search modes: Text, Image, Voice, Chatbot (4 modes)
- Scoring: 9-signal ensemble engine
- Accuracy: Top-1: 88.5% | Top-5: 98.0% | Top-10: 99.5%
- Training: 99.8% | Validation: 98.0%
- Voice: faster-whisper (fully offline)"""
        lang_instruction = "\n[Reply in English only]"

    messages = [{"role": "system", "content": system_prompt}]
    for h in history[-6:]:
        messages.append({"role": h["role"], "content": h["content"]})
    # ✅ نضيف تعليمة اللغة في نهاية رسالة المستخدم — هذا يضمن اتباعها
    messages.append({"role": "user", "content": user_msg + lang_instruction})

    try:
        import requests as _req
        res = _req.post(
            "https://api.groq.com/openai/v1/chat/completions",
            headers={"Authorization": f"Bearer {GROQ_API_KEY}", "Content-Type": "application/json"},
            json={"model": "llama-3.1-8b-instant", "messages": messages, "max_tokens": 300, "temperature": 0.2},
            timeout=15
        )
        if res.status_code != 200:
            return "⚠️ تعذّر الاتصال بـ Groq حالياً." if is_arabic else "⚠️ Unable to reach Groq right now."
        data = res.json()
        if "choices" not in data or not data["choices"]:
            return "⚠️ لم يتم استلام رد صحيح." if is_arabic else "⚠️ Invalid response received."
        return data["choices"][0]["message"]["content"].strip()
    except Exception:
        return "⚠️ تعذّر الاتصال بالمساعد حالياً. حاول مرة أخرى بعد قليل." if is_arabic             else "⚠️ The assistant is temporarily unavailable. Please try again shortly."



# ============================================================
#                   SEARCH PAGE
# ============================================================
def search_page():
    st.markdown(get_css(), unsafe_allow_html=True)
    # ===== Cosmic Background =====
    _bg_b64 = GALAXY_BG_B64 if st.session_state.dark_mode else LIGHT_BG_B64
    _bg_type = "image/png" if st.session_state.dark_mode else "image/jpeg"
    st.markdown(f'<div style="position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;"><img src="data:{_bg_type};base64,{_bg_b64}" style="width:100%;height:100%;object-fit:cover;" alt=""></div>', unsafe_allow_html=True)
    st.markdown('<div class="card">', unsafe_allow_html=True)

    col_icon, col_mode = st.columns([6, 1])
    with col_icon:
        st.markdown(f"""
        <div style="text-align:center; margin-bottom:6px;">
            <div style="display:inline-block; text-align:center;">
                <img src="{ICONS['camera_big']}" style="width:130px; height:130px; filter:drop-shadow(0 6px 14px rgba(155,109,215,0.3)); margin-top:0px; margin-bottom:0px;" alt="mascot">
            </div>
        </div>
        """, unsafe_allow_html=True)
    with col_mode:
        mode_label = "☀️" if st.session_state.dark_mode else "🌙"
        if st.button(mode_label, key="dark_toggle"):
            st.session_state.dark_mode = not st.session_state.dark_mode
            st.rerun()

    st.markdown(
        f'<h1 class="main-title" style="text-align:center; color:#ffffff; -webkit-text-fill-color:#ffffff; font-size:40px; font-weight:900; margin:0 0 2px 0; font-family:Poppins,sans-serif; font-style:italic; line-height:1.08; letter-spacing:-1px; text-shadow:0 4px 12px rgba(0,0,0,0.45),0 0 18px rgba(255,255,255,0.25);">Advanced Search Platform</h1>',
        unsafe_allow_html=True)
    st.markdown(
        f'<p class="subtitle" style="text-align:center; color:#ffffff; -webkit-text-fill-color:#ffffff; font-size:15px; margin:0 0 4px 0; font-family:Poppins,sans-serif; font-weight:700; letter-spacing:0.3px; opacity:0.95; text-shadow:0 2px 8px rgba(0,0,0,0.45),0 0 10px rgba(255,255,255,0.18);">AI-Powered Visual Content Discovery Technology</p>',
        unsafe_allow_html=True)

    # --- 7 Tabs (added Feedback) ---
    tab_search, tab_image, tab_voice, tab_chat, tab_eval, tab_stats, tab_feedback = st.tabs([
        "  Search", "  Image", "  Voice", "  Chat", "  Eval", "  Stats", "  Feedback"
    ])

    # ==================== TEXT SEARCH ====================
    # ==================== TEXT SEARCH ====================
    with tab_search:
        # ✅ Language Selector + Query Input
        col_query, col_lang = st.columns([3, 1])
        with col_query:
            query = st.text_input("Enter Search Query", placeholder="Search for any video content...")
        with col_lang:
            language = st.selectbox(
                "🌍 Language",
                options=["🇬🇧 English", "🇸🇦 العربية", "🇫🇷 Français", "🇪🇸 Español", "🇹🇷 Türkçe"],
                index=0,
                key="search_lang"
            )

        colA, colB, colC, colD = st.columns(4)
        with colA:
            top_k = st.number_input("Top K", min_value=1, max_value=100, value=10, step=1)
        with colB:
            min_score = st.slider("Min Score", 0.0, 1.0, 0.20, 0.01)
        with colC:
            show_video = st.checkbox("Show Video", value=True)
        with colD:
            category = st.selectbox("Category", list(CATEGORIES.keys()))

        search_clicked = st.button("✦ EXECUTE SEARCH ✦", use_container_width=True, key="text_search_btn")

        st.markdown(f"""
        <div style="display:flex; gap:10px; margin-top:12px;">
          <div class="kpi" style="flex:1;padding:14px 8px;"><div style="display:flex;align-items:center;justify-content:center;gap:4px;margin-bottom:4px;">
                <img src="{ICONS['kpi_clips_clapper']}" style="width:40px;height:40px;" alt="">
                <img src="{ICONS['kpi_clips_reels']}" style="width:40px;height:40px;" alt="">
            </div><div class="big" style="font-size:28px;">7K+</div><div class="small" style="font-size:13px;">Video Clips</div></div>
          <div class="kpi" style="flex:1;padding:14px 8px;"><div style="display:flex;align-items:center;justify-content:center;gap:4px;margin-bottom:4px;">
                <img src="{ICONS['kpi_speed_compass']}" style="width:40px;height:40px;" alt="">
                <img src="{ICONS['kpi_speed_stopwatch']}" style="width:40px;height:40px;" alt="">
            </div><div class="big" style="font-size:28px;">0.3s</div><div class="small" style="font-size:13px;">Search Speed</div></div>
          <div class="kpi" style="flex:1;padding:14px 8px;"><div style="display:flex;align-items:center;justify-content:center;gap:4px;margin-bottom:4px;">
                <img src="{ICONS['kpi_accuracy_chart']}" style="width:40px;height:40px;" alt="">
                <img src="{ICONS['kpi_accuracy_gems']}" style="width:40px;height:40px;" alt="">
            </div><div class="big" style="font-size:28px;">99.5%</div><div class="small" style="font-size:13px;">Top-10 Accuracy</div></div>
        </div>
        """, unsafe_allow_html=True)

        if search_clicked:
            q = (query or "").strip()
            if not q:
                st.warning("اكتب جملة بحث أول.")
                st.stop()
            with st.spinner("⚡ Searching..."):
                results, avg = semantic_search(q, top_k=int(top_k), min_score=float(min_score), verbose=False)
            if not results:
                st.error("⚠️ هذا المحتوى غير موجود في قاعدة البيانات. جرّب: dog running, cooking food, playing guitar")
                st.stop()
            if category != "All":
                cat_kw = CATEGORIES[category]
                filtered = [r for r in results if any(kw in f"{r['title']} {r['caption']}".lower() for kw in cat_kw)]
                if filtered:
                    results = filtered
            st.session_state.results = results
            st.session_state.avg_score = avg
            st.session_state.search_query = q
            st.session_state.show_video_flag = show_video
            # ✅ تسجيل البحث في قاعدة البيانات
            try:
                save_search(query=q, search_type="text", results_count=len(results), avg_score=avg, top_k=int(top_k))
            except Exception:
                pass
            st.session_state.page = "results"
            st.rerun()

    # ==================== IMAGE SEARCH ====================
    with tab_image:
        st.markdown(f'<p style="color:{C["PRIMARY"]}; font-size:16px; font-weight:800;">🖼️ Search by Image</p>',
                    unsafe_allow_html=True)
        uploaded_img = st.file_uploader("Upload Image", type=["jpg", "jpeg", "png"])
        img_top_k = st.number_input("Results", min_value=1, max_value=50, value=5, step=1, key="img_k")
        if st.button("🔍 Search by Image", use_container_width=True, key="img_btn"):
            if uploaded_img:
                image = Image.open(uploaded_img).convert("RGB")
                st.image(image, caption="Uploaded", width=250)
                with st.spinner("🔍 جاري تحليل الصورة..."):
                    results, avg = image_search(image, top_k=int(img_top_k))
                if results:
                    st.session_state.results = results
                    st.session_state.avg_score = avg
                    st.session_state.search_query = "🖼️ Image Search"
                    st.session_state.show_video_flag = True
                    st.session_state.page = "results"
                    st.rerun()
                else:
                    st.error("⚠️ هذا المحتوى غير موجود في الداتاسيت — جرّب صورة رياضة، طبخ، أو حيوانات شائعة")
            else:
                st.warning("⚠️ ارفع صورة أول.")

    # ==================== VOICE SEARCH ====================
    with tab_voice:
        st.markdown(f'<p style="color:{C["PRIMARY"]}; font-size:16px; font-weight:800;">🎤 Voice Search</p>',
                    unsafe_allow_html=True)
        st.markdown(
            f'<p style="color:{C["TEXT_LIGHT"]}; font-size:14px;">اضغط على الميكروفون وتكلم — النظام يحوّل صوتك لنص ويبحث</p>',
            unsafe_allow_html=True)

        from streamlit_mic_recorder import mic_recorder
        import tempfile

        voice_lang = st.radio(
            "🌍 لغة الكلام:",
            options=["🇸🇦 عربي", "🇬🇧 English"],
            horizontal=True,
            key="voice_lang_select"
        )
        whisper_lang = "ar" if "عربي" in voice_lang else "en"
        model_size  = "small" if whisper_lang == "ar" else "base"

        voice_top_k = st.number_input("عدد النتائج", min_value=1, max_value=50, value=5, step=1, key="voice_k")

        audio = mic_recorder(
            start_prompt="🎤 اضغط وتكلم",
            stop_prompt="⏹️ إيقاف التسجيل",
            just_once=True,
            key="voice_rec"
        )

        if audio:
            st.audio(audio["bytes"], format="audio/wav")
            with st.spinner("🔄 جاري تحويل الصوت لنص..."):
                try:
                    with tempfile.NamedTemporaryFile(suffix=".wav", delete=False) as tmp:
                        tmp.write(audio["bytes"])
                        tmp_path = tmp.name

                    try:
                        from faster_whisper import WhisperModel
                    except ImportError:
                        st.error("❌ ثبّتي: pip install faster-whisper")
                        os.remove(tmp_path)
                        st.stop()

                    model_key = f"fw_model_{model_size}"
                    if model_key not in st.session_state:
                        with st.spinner(f"⏳ تحميل النموذج {model_size}..."):
                            st.session_state[model_key] = WhisperModel(
                                model_size, device="cpu", compute_type="int8"
                            )
                    model = st.session_state[model_key]

                    initial_prompt = "هذا نص عربي فصيح أو عامي." if whisper_lang == "ar" else None
                    segments, info = model.transcribe(
                        tmp_path,
                        language=whisper_lang,
                        beam_size=5,
                        best_of=5,
                        temperature=0.0,
                        condition_on_previous_text=False,
                        initial_prompt=initial_prompt,
                        vad_filter=True,
                        vad_parameters=dict(min_silence_duration_ms=300)
                    )
                    text = " ".join([seg.text.strip() for seg in segments]).strip()
                    os.remove(tmp_path)

                    if not text:
                        st.warning("⚠️ لم يُكتشف صوت. تكلّمي بوضوح وقرّبي الميكروفون.")
                        st.stop()

                    st.success(f'🗣️ سمعت: "{text}"')

                    # ✅ نمرر النص مباشرة لـ semantic_search
                    # الـ ai_engine يتولى الترجمة الذكية (Google Translate + قاموس متقدم)
                    with st.spinner("🔍 جاري البحث..."):
                        results, avg = semantic_search(
                            text,
                            top_k=int(voice_top_k),
                            min_score=0.20,
                            verbose=False
                        )

                    if not results:
                        st.error("⚠️ هذا المحتوى غير موجود. جرّب: كلب يجري، رجل يطبخ، كرة قدم")
                    else:
                        st.session_state.results  = results
                        st.session_state.avg_score = avg
                        st.session_state.search_query = f"🎤 {text}"
                        st.session_state.show_video_flag = True
                        st.session_state.page = "results"
                        st.rerun()

                except Exception as e:
                    st.error(f"❌ خطأ: {str(e)}")
                    if 'tmp_path' in locals() and os.path.exists(tmp_path):
                        os.remove(tmp_path)
        st.markdown(
            f"<p style='color:{C['TEXT_MID']}; font-size:14px; font-weight:600; margin-top:15px;'>🔤 بحث سريع:</p>",
            unsafe_allow_html=True)
        quick_cols = st.columns(4)
        quick_words = [("🐕 كلب", "dog"), ("🍳 طبخ", "cooking"), ("⚽ كرة قدم", "football"), ("🎸 جيتار", "guitar")]
        for i, (ar, en) in enumerate(quick_words):
            with quick_cols[i]:
                if st.button(ar, key=f"quick_{i}", use_container_width=True):
                    with st.spinner("🔍 ..."):
                        results, avg = semantic_search(en, top_k=5, min_score=0.20, verbose=False)
                    if results:
                        st.session_state.results = results
                        st.session_state.avg_score = avg
                        st.session_state.search_query = f"🎤 {ar} → {en}"
                        st.session_state.show_video_flag = True
                        st.session_state.page = "results"
                        st.rerun()

    # ==================== CHATBOT ====================
    with tab_chat:
        st.markdown(
            f'<p style="color:{C["PRIMARY"]}; font-size:16px; font-weight:800;">' +
            '💬 Project Assistant ' +
            '<span style="font-size:16px;background:linear-gradient(135deg,#93c5fd,#c4b5fd);color:white;padding:2px 10px;border-radius:10px;">Groq ⚡</span></p>',
            unsafe_allow_html=True)
        for msg in st.session_state.chat_history:
            if msg["role"] == "user":
                user_ar = any('\u0600' <= c <= '\u06ff' for c in msg["text"])
                u_class = "chat-user-ar" if user_ar else "chat-user"
                st.markdown(f'<div class="{u_class}">{msg["text"]}</div>', unsafe_allow_html=True)
            else:
                # ✅ كلاس مختلف حسب لغة الرد
                has_arabic = any('\u0600' <= c <= '\u06ff' for c in msg["text"])
                css_class = "chat-bot-ar" if has_arabic else "chat-bot"
                st.markdown(f'<div class="{css_class}">{msg["text"]}</div>', unsafe_allow_html=True)
        user_input = st.text_input("اكتب سؤالك...", key="chat_input",
                                   placeholder="مثال: وش دقة النظام؟ | How does CLIP work?")
        col_s, col_c = st.columns([3, 1])
        with col_s:
            send = st.button("إرسال ➤", key="chat_send", use_container_width=True)
        with col_c:
            if st.button("🗑️", key="chat_clear", use_container_width=True):
                st.session_state.chat_history = []
                st.rerun()
        if send and user_input.strip():
            groq_history = [
                {"role": "user" if m["role"] == "user" else "assistant", "content": m["text"]}
                for m in st.session_state.chat_history
            ]
            st.session_state.chat_history.append({"role": "user", "text": user_input.strip()})
            with st.spinner("🤖 ..."):
                reply = chatbot_reply(user_input, history=groq_history)
            st.session_state.chat_history.append({"role": "bot", "text": reply})
            st.rerun()
        st.markdown(f"<p style='color:{C['TEXT_MUTED']}; font-size:16px;'>⚡ Groq llama-3.1-8b-instant</p>",
                    unsafe_allow_html=True)

    # ==================== EVALUATION ====================
    with tab_eval:
        st.markdown(
            f'<p style="text-align:center; color:{C["TEXT_DARK"]}; font-size:20px; font-weight:800;">📊 Evaluation Results</p>',
            unsafe_allow_html=True)
        if os.path.exists(EVAL_RESULTS_CSV):
            eval_df = pd.read_csv(EVAL_RESULTS_CSV, encoding="utf-8")
            n = len(eval_df)
            hits_1 = int(eval_df["hit@1"].sum()) if "hit@1" in eval_df.columns else 0
            hits_5 = int(eval_df["hit@5"].sum()) if "hit@5" in eval_df.columns else 0
            hits_10 = int(eval_df["hit@10"].sum()) if "hit@10" in eval_df.columns else 0
            acc1 = hits_1 / max(n, 1);
            acc5 = hits_5 / max(n, 1);
            acc10 = hits_10 / max(n, 1)
            st.markdown(f"""
            <div style="display:flex; gap:14px; margin:16px 0 32px 0;">
                <div class="kpi" style="flex:1;"><div class="big" style="color:{'#22c55e' if acc1 >= 0.6 else C['PRIMARY']};">{acc1:.1%}</div><div class="small">Top-1</div><div style="color:{C['TEXT_MUTED']}; font-size:16px;">{hits_1}/{n}</div></div>
                <div class="kpi" style="flex:1;"><div class="big" style="color:{'#22c55e' if acc5 >= 0.7 else C['PRIMARY']};">{acc5:.1%}</div><div class="small">Top-5</div><div style="color:{C['TEXT_MUTED']}; font-size:16px;">{hits_5}/{n}</div></div>
                <div class="kpi" style="flex:1;"><div class="big" style="color:{'#22c55e' if acc10 >= 0.8 else C['PRIMARY']};">{acc10:.1%}</div><div class="small">Top-10</div><div style="color:{C['TEXT_MUTED']}; font-size:16px;">{hits_10}/{n}</div></div>
            </div>
            """, unsafe_allow_html=True)
            if acc10 >= 0.8:
                st.success(f"🏆 Excellent! Top-10 = {acc10:.1%}")
            elif acc10 >= 0.5:
                st.info(f"👍 Good. Top-10 = {acc10:.1%}")
            if "eval_details_open" not in st.session_state:
                st.session_state.eval_details_open = False
            st.markdown("<div style='height:12px'></div>", unsafe_allow_html=True)
            if st.button("📋 Details  ▾" if not st.session_state.eval_details_open else "📋 Details  ▴",
                         key="eval_details_btn", use_container_width=True):
                st.session_state.eval_details_open = not st.session_state.eval_details_open
            if st.session_state.eval_details_open:
                st.markdown(f"""
                <div style="background:rgba(255,255,255,0.08); border:1px solid rgba(255,255,255,0.18);
                     border-radius:14px; padding:16px 20px; margin-top:8px;">
                """, unsafe_allow_html=True)
                for idx, row in eval_df.iterrows():
                    q = str(row.get("query", ""))[:55]
                    h10 = int(row.get("hit@10", 0))
                    icon = "✅" if h10 else "❌"
                    st.markdown(
                        f"<p style='color:#ffffff; font-size:13px; margin:4px 0;'>"
                        f"{icon} <b>#{idx + 1}</b> \"{q}\"</p>",
                        unsafe_allow_html=True)
                st.markdown("</div>", unsafe_allow_html=True)
        else:
            st.warning("⚠️ Run `python eval_accuracy.py` first.")

    # ==================== STATISTICS ====================
    with tab_stats:
        st.markdown(
            f'<p style="text-align:center; color:{C["TEXT_DARK"]}; font-size:20px; font-weight:800;">📈 Dataset Statistics</p>',
            unsafe_allow_html=True)
        if os.path.exists(DATASET_CSV):
            df_s = pd.read_csv(DATASET_CSV, encoding="utf-8")
            df_s["Caption"] = df_s["Caption"].fillna("").astype(str)
            df_s["Title"] = df_s["Title"].fillna("").astype(str)
            total = len(df_s)
            avg_len = df_s["Caption"].str.split().str.len().mean()
            st.markdown(f"""
            <div style="display:flex; gap:14px; margin:16px 0 32px 0;">
                <div class="kpi" style="flex:1;"><div class="big">{total:,}</div><div class="small">Total Videos</div></div>
                <div class="kpi" style="flex:1;"><div class="big">{avg_len:.0f}</div><div class="small">Avg Caption Words</div></div>
                <div class="kpi" style="flex:1;"><div class="big">{len(CATEGORIES) - 1}</div><div class="small">Categories</div></div>
            </div>
            """, unsafe_allow_html=True)
            st.markdown(
                f"<p style='color:{C['TEXT_DARK']}; font-size:16px; font-weight:700;'>📊 Caption Length Distribution</p>",
                unsafe_allow_html=True)
            st.bar_chart(df_s["Caption"].str.split().str.len().value_counts().sort_index().head(30))
            st.markdown(
                f"<p style='color:{C['TEXT_DARK']}; font-size:16px; font-weight:700;'>🏷️ Category Distribution</p>",
                unsafe_allow_html=True)
            cat_counts = {}
            for cat, kws in CATEGORIES.items():
                if cat == "All": continue
                cnt = sum(
                    1 for _, r in df_s.iterrows() if any(k in f"{r['Title']} {r['Caption']}".lower() for k in kws))
                cat_counts[cat] = cnt
            st.bar_chart(
                pd.DataFrame({"Category": list(cat_counts.keys()), "Count": list(cat_counts.values())}).set_index(
                    "Category"))
            st.markdown(f"<p style='color:{C['TEXT_DARK']}; font-size:16px; font-weight:700;'>🔤 Top Words</p>",
                        unsafe_allow_html=True)
            from collections import Counter
            words = " ".join(df_s["Caption"].str.lower()).split()
            stop = {"a", "an", "the", "is", "are", "was", "were", "in", "on", "at", "to", "of", "and", "or", "with",
                    "that", "this", "it", "for", "he", "she", "they", "his", "her", "man", "woman", "person", "video"}
            wc = Counter(w for w in words if w not in stop and len(w) > 2).most_common(20)
            st.bar_chart(pd.DataFrame(wc, columns=["Word", "Count"]).set_index("Word"))

    # ==================== FEEDBACK TAB ====================
    with tab_feedback:
        st.markdown(
            f'<p style="text-align:center; color:{C["TEXT_DARK"]}; font-size:20px; font-weight:800;">📋 User Feedback</p>',
            unsafe_allow_html=True)
        stats = get_feedback_stats()
        st.markdown(f"""
        <div style="display:flex; gap:14px; margin:16px 0 32px 0;">
            <div class="kpi" style="flex:1;"><div class="big" style="color:{C['PRIMARY']};">{stats['total']}</div><div class="small">Total Ratings</div></div>
            <div class="kpi" style="flex:1;"><div class="big" style="color:#22c55e;">👍 {stats['thumbs_up']}</div><div class="small">Positive</div></div>
            <div class="kpi" style="flex:1;"><div class="big" style="color:#ef4444;">👎 {stats['thumbs_down']}</div><div class="small">Negative</div></div>
            <div class="kpi" style="flex:1;"><div class="big" style="color:{'#22c55e' if stats['satisfaction_rate'] >= 70 else '#ef4444'};">{stats['satisfaction_rate']:.1f}%</div><div class="small">Satisfaction</div></div>
        </div>
        """, unsafe_allow_html=True)
        if stats['total'] > 0:
            if stats['satisfaction_rate'] >= 80:
                st.success(f"🏆 ممتاز! نسبة الرضا {stats['satisfaction_rate']:.1f}%")
            elif stats['satisfaction_rate'] >= 60:
                st.info(f"👍 جيد! نسبة الرضا {stats['satisfaction_rate']:.1f}%")
            else:
                st.warning(f"⚠️ يحتاج تحسين - نسبة الرضا {stats['satisfaction_rate']:.1f}%")
        st.markdown(
            f"<p style='color:{C['TEXT_DARK']}; font-size:16px; font-weight:700; margin-top:20px;'>📝 آخر التقييمات:</p>",
            unsafe_allow_html=True)
        feedback = load_feedback()
        if feedback:
            for fb in reversed(feedback[-10:]):
                rating_emoji = "👍" if fb["rating"] == "up" else "👎"
                rating_color = "#22c55e" if fb["rating"] == "up" else "#ef4444"
                st.markdown(f"""
                <div style="background:{C['CARD_BG']}; border-left:3px solid {rating_color}; border-radius:8px; padding:12px; margin:8px 0;">
                    <div style="display:flex; justify-content:space-between; align-items:center;">
                        <div><span style="font-size:20px;">{rating_emoji}</span> <span style="color:{C['TEXT_DARK']}; font-weight:600;">"{fb['query']}"</span></div>
                        <span style="color:{C['TEXT_MUTED']}; font-size:12px;">{fb['timestamp']}</span>
                    </div>
                    <div style="color:{C['TEXT_LIGHT']}; font-size:12px; margin-top:4px;">📁 {fb['video_link'][:50]}...</div>
                </div>
                """, unsafe_allow_html=True)
        else:
            st.info("لا توجد تقييمات بعد. ابدأ بالبحث وتقييم النتائج!")
        if feedback:
            if st.button("📥 تصدير التقييمات (CSV)", use_container_width=True):
                df_fb = pd.DataFrame(feedback)
                csv = df_fb.to_csv(index=False, encoding='utf-8-sig')
                st.download_button("⬇️ تحميل", data=csv, file_name=f"feedback_{datetime.now().strftime('%Y%m%d')}.csv",
                                   mime="text/csv")

    st.markdown('</div>', unsafe_allow_html=True)


# ============================================================
#                   RESULTS PAGE (with 👍👎)
# ============================================================
def results_page():
    results = st.session_state.results
    avg = st.session_state.avg_score
    query = st.session_state.search_query
    show_video = st.session_state.show_video_flag
    total = len(results)

    st.markdown(get_css(), unsafe_allow_html=True)
    _bg_b64 = GALAXY_BG_B64 if st.session_state.dark_mode else LIGHT_BG_B64
    _bg_type = "image/png" if st.session_state.dark_mode else "image/jpeg"
    st.markdown(f'<div style="position:fixed;top:0;left:0;width:100%;height:100%;z-index:0;pointer-events:none;"><img src="data:{_bg_type};base64,{_bg_b64}" style="width:100%;height:100%;object-fit:cover;" alt=""></div>', unsafe_allow_html=True)
    st.markdown(f"""
    <style>
    .result-card {{ background:{C['RESULT_BG']}; border:2px solid {C['RESULT_BORDER']}; border-radius:18px; padding:22px; max-width:860px; margin:14px auto; transition:all 0.3s ease; box-shadow:0 5px 20px {C['SHADOW']}; }}
    .result-card:hover {{ border-color:{C['RESULT_HOVER']}; transform:translateY(-2px); }}
    .result-title {{ color:{C['TEXT_DARK']}; font-size:20px; font-weight:700; }}
    .result-caption {{ color:{C['TEXT_LIGHT']}; font-size:16px; margin-top:8px; }}
    .score-badge {{ display:inline-block; background:{BADGE_GRAD}; color:white; padding:5px 16px; border-radius:14px; font-weight:700; font-size:14px; }}
    .rank-num {{ display:inline-flex; align-items:center; justify-content:center; width:36px; height:36px; border-radius:50%; background:rgba(147,197,253,0.25); color:{C['PRIMARY']}; font-weight:800; font-size:16px; margin-right:12px; }}
    .link-box {{ background:{C['CARD_BG']}; border:1px solid {C['RESULT_BORDER']}; border-radius:10px; padding:10px 14px; color:{C['TEXT_MUTED']}; font-size:13px; font-family:monospace; margin-top:12px; }}
    </style>
    """, unsafe_allow_html=True)

    if st.button("← Back to Search"):
        st.session_state.page = "search"
        st.rerun()

    st.markdown(f"""
    <div style="background:{C['CARD_BG']}; border:2px solid {C['BORDER']}; border-radius:18px; padding:24px; max-width:860px; margin:20px auto;">
        <p style="color:{C['TEXT_DARK']}; font-size:28px; font-weight:800; margin:0;">Search Results</p>
        <p style="color:{C['TEXT_LIGHT']}; font-size:15px; margin-top:6px;">Query: <b style="color:{C['PRIMARY']};">{query}</b></p>
        <div style="display:flex; gap:12px; margin-top:14px;">
            <span style="background:rgba(147,197,253,0.2); border:1px solid {C['BORDER']}; color:{C['PRIMARY']}; padding:6px 14px; border-radius:99px; font-size:14px; font-weight:600;">📊 Avg: {avg}</span>
            <span style="background:rgba(147,197,253,0.2); border:1px solid {C['BORDER']}; color:{C['PRIMARY']}; padding:6px 14px; border-radius:99px; font-size:14px; font-weight:600;">🎬 {total} Videos</span>
        </div>
    </div>
    """, unsafe_allow_html=True)

    for i, r in enumerate(results, start=1):
        search_query_used = st.session_state.get("search_query", "")
        kw_badge = ""
        display_query = search_query_used.replace("🎤 ", "").replace("🔍 ", "").replace("🖼️ ", "")
        if "→" in display_query:
            display_query = display_query.split("→")[-1].strip()
        caption_lower = r.get("caption", "").lower()
        title_lower = r.get("title", "").lower()
        combined = caption_lower + " " + title_lower
        import re as _re
        # ✅ قائمة stop words شاملة — لا تُحسب كـ keywords
        _stop = {
            "a","an","the","is","are","was","were","be","been","being",
            "in","on","at","to","of","and","or","with","for","from",
            "that","this","it","its","he","she","they","his","her",
            "man","woman","person","people","video","some","has","have",
            "had","do","does","did","will","would","can","could","may",
            "not","but","by","as","up","out","so","if","about","into",
            "go","get","got","one","two","all","who","what","which","how",
            "children","child","girl","boy","young","old","new","other",
        }
        query_words = [
            w for w in display_query.lower().split()
            if len(w) > 3 and w not in _stop
        ]
        matched_words = [w for w in query_words if _re.search(r'\b' + _re.escape(w) + r'\b', combined)]
        if matched_words:
            # ✅ عرض الجملة كاملة بدل الكلمات المفرقة بفواصل
            kw_badge = f"<div style='margin-top:10px; padding:8px 12px; background:#d1fae5; border-left:3px solid #10b981; border-radius:6px;'><span style='color:#065f46; font-size:13px; font-weight:600;'>✓ Matched: {display_query}</span></div>"
        elif display_query:
            kw_badge = f"<div style='margin-top:10px; padding:8px 12px; background:#fef3c7; border-left:3px solid #f59e0b; border-radius:6px;'><span style='color:#92400e; font-size:13px; font-weight:600;'>🔍 Semantic: {display_query}</span></div>"

        st.markdown(f"""
        <div class="result-card">
            <div style="display:flex; justify-content:space-between; align-items:center;">
                <div style="display:flex; align-items:center;">
                    <span class="rank-num">{i}</span>
                    <span class="result-title">{r.get('title', '')}</span>
                </div>
                <span class="score-badge">Score: {r.get('score', 0)}</span>
            </div>
            {"<p class='result-caption'>" + r.get('caption', '') + "</p>" if r.get('caption') else ""}
            {kw_badge}
            <div class="link-box">📁 {r.get('link', '')}</div>
        </div>
        """, unsafe_allow_html=True)

        # ✅ Video + Feedback buttons
        col_video, col_feedback = st.columns([4, 1])
        with col_video:
            if show_video and os.path.exists(r.get("link", "")):
                st.video(r["link"])
        with col_feedback:
            st.markdown(
                f"<div style='text-align:center; padding:8px; background:{C['CARD_BG']}; border:1px solid {C['BORDER']}; border-radius:10px;'><p style='color:{C['TEXT_MID']}; font-size:12px; margin:0;'>مفيدة؟</p></div>",
                unsafe_allow_html=True)
            col_up, col_down = st.columns(2)
            with col_up:
                if st.button("👍", key=f"up_{i}", use_container_width=True):
                    if save_feedback(query, r.get('link', ''), "up"):
                        st.success("✅")
            with col_down:
                if st.button("👎", key=f"down_{i}", use_container_width=True):
                    if save_feedback(query, r.get('link', ''), "down"):
                        st.info("📝")


# ============================================================
if st.session_state.page == "search":
    search_page()
elif st.session_state.page == "results":
    results_page()
